defmodule AdminDashboardWeb.UserController do
  use Phoenix.Controller
  alias AdminDashboard.Users

  def index(conn, params) do
    case params do
      %{"role" => role} ->
        case Users.list_users_by_role(role) do
          {:ok, users} ->
            json(conn, %{users: users})
          {:error, _} ->
            conn
            |> put_status(:internal_server_error)
            |> json(%{error: "Failed to fetch users"})
        end
      
      _ ->
        conn
        |> put_status(:bad_request)
        |> json(%{error: "Missing required parameters"})
    end
  end

  def search(conn, params) do
    search_params = %{}
    
    search_params = if role = params["role"], do: Map.put(search_params, :role, role), else: search_params
    search_params = if email = params["email_contains"], do: Map.put(search_params, :email_contains, email), else: search_params
    search_params = if min_id = params["min_id"], do: Map.put(search_params, :min_id, String.to_integer(min_id)), else: search_params
    
    case Users.search_users(search_params) do
      {:ok, users} ->
        json(conn, %{users: users})
      {:error, _} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Failed to search users"})
    end
  end

  def show(conn, %{"id" => id}) do
    case Users.get_user_by_id(String.to_integer(id)) do
      {:ok, user} ->
        json(conn, %{user: user})
      {:error, :not_found} ->
        conn
        |> put_status(:not_found)
        |> json(%{error: "User not found"})
      {:error, _} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Failed to fetch user"})
    end
  end

  def filter(conn, params) do
    filter_params = %{}
    
    filter_params = if role = params["role"], do: Map.put(filter_params, :role, role), else: filter_params
    filter_params = if email = params["email"], do: Map.put(filter_params, :email, email), else: filter_params
    filter_params = if active = params["active"], do: Map.put(filter_params, :active, active == "true"), else: filter_params
    filter_params = if sort_col = params["sort_column"], do: Map.put(filter_params, :sort_column, sort_col), else: filter_params
    filter_params = if sort_dir = params["sort_direction"], do: Map.put(filter_params, :sort_direction, String.upcase(sort_dir)), else: filter_params
    filter_params = if limit = params["limit"], do: Map.put(filter_params, :limit, String.to_integer(limit)), else: filter_params
    
    case Users.complex_filter(filter_params) do
      {:ok, users} ->
        json(conn, %{users: users})
      {:error, _} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{error: "Failed to filter users"})
    end
  end
end